-- LOCAL DEV SEED - generated by app/scripts/gen-seed.mjs from a demo-mode snapshot.
-- Creates a fixed email/password test user (e2e@finapp.local) plus the demo dataset for it,
-- so agents / e2e can sign in to real PowerSync mode without Google OAuth.
-- Local only: the password is not a secret. Applied by `supabase db reset`.

begin;

-- Idempotent reset of the test user and its data (no-op on a fresh reset).
delete from public.trns where "userId" = 'e2e00000-0000-4000-8000-000000000001';
delete from public.wallets where "userId" = 'e2e00000-0000-4000-8000-000000000001';
delete from public.categories where "userId" = 'e2e00000-0000-4000-8000-000000000001';
delete from public.user_settings where "userId" = 'e2e00000-0000-4000-8000-000000000001';
delete from auth.identities where user_id = 'e2e00000-0000-4000-8000-000000000001'::uuid;
delete from auth.users where id = 'e2e00000-0000-4000-8000-000000000001'::uuid or email = 'e2e@finapp.local';

-- Auth user (email provider) + identity. crypt/gen_salt come from pgcrypto (extensions schema).
-- The token columns must be '' (not NULL): GoTrue scans them as strings and a NULL
-- triggers "Database error querying schema" on sign-in.
  instance_id, id, aud, role, email, encrypted_password,
  email_confirmed_at, created_at, updated_at, raw_app_meta_data, raw_user_meta_data,
  is_sso_user, is_anonymous,
  confirmation_token, recovery_token, email_change, email_change_token_new,
  email_change_token_current, phone_change, phone_change_token, reauthentication_token
) values (
  '00000000-0000-0000-0000-000000000000', 'e2e00000-0000-4000-8000-000000000001'::uuid, 'authenticated', 'authenticated',
  'e2e@finapp.local', extensions.crypt('finapp-e2e', extensions.gen_salt('bf')),
  now(), now(), now(), '{"provider":"email","providers":["email"]}', '{}', false, false,
  '', '', '', '', '', '', '', ''
);

  provider_id, user_id, identity_data, provider, last_sign_in_at, created_at, updated_at
) values (
  'e2e00000-0000-4000-8000-000000000001', 'e2e00000-0000-4000-8000-000000000001'::uuid,
  jsonb_build_object('sub', 'e2e00000-0000-4000-8000-000000000001', 'email', 'e2e@finapp.local'),
  'email', now(), now(), now()
);

-- user_settings (the on_auth_user_created trigger inserts a default row; pin currency/locale).
  values ('e2e00000-0000-4000-8000-000000000001', 'e2e00000-0000-4000-8000-000000000001', 'USD', 'en')
  on conflict (id) do update set "baseCurrency" = excluded."baseCurrency", locale = excluded.locale;

-- Domain data (from demo): 8 wallets, 32 categories, 860 trns.



commit;
